---
import type { ImageMetadata } from "astro"

import { cn } from "@/lib/utils"
import {
  Avatar,
  AvatarFallback,
  AvatarGroup,
  AvatarGroupCount,
  AvatarImage,
} from "@/components/ui/avatar"
import { Button } from "@/components/ui/button"
import { Section, SectionContainer } from "@/components/ui/section"

type Props = {
  class?: string
  title: string
  description: string
  buttons?: {
    label: string
    href: string
    variant?: "default" | "outline" | "secondary" | "ghost"
  }[]
  socialProof?: {
    avatars: {
      image?: ImageMetadata
      initials: string
      name?: string
    }[]
    count?: string | number
    rating?: number
    text: string
  }
}

const {
  class: className,
  title,
  description,
  buttons,
  socialProof,
} = Astro.props
---

<Section class={cn("bg-primary/10 border-primary/15 border-y", className)}>
  <SectionContainer class="items-center text-center">
    <div class="flex max-w-2xl flex-col items-center gap-5">
      <h2
        class="text-foreground text-3xl leading-[1.1] font-semibold tracking-tight text-balance sm:text-4xl"
      >
        {title}
      </h2>
      <p class="text-muted-foreground text-lg leading-relaxed text-balance">
        {description}
      </p>
    </div>
    {
      buttons?.length && (
        <div class="flex flex-wrap justify-center gap-3">
          {buttons.map(({ href, label, ...button }, index) => (
            <Button
              as="a"
              href={href}
              size="lg"
              variant={
                button.variant ?? (index === 0 ? "default" : "secondary")
              }
              {...button}
            >
              {label}
            </Button>
          ))}
        </div>
      )
    }
    {
      socialProof && (
        <div class="flex flex-col items-center gap-2">
          <AvatarGroup>
            {socialProof.avatars.map((avatar) => (
              <Avatar class="ring-primary/10 bg-background size-11 ring">
                <AvatarImage
                  src={avatar.image}
                  alt={avatar.name ?? avatar.initials}
                />
                <AvatarFallback>{avatar.initials}</AvatarFallback>
              </Avatar>
            ))}
            {socialProof.count && (
              <AvatarGroupCount class="bg-background text-foreground ring-primary/10 size-11 ring">
                {socialProof.count}
              </AvatarGroupCount>
            )}
          </AvatarGroup>
          <span class="text-muted-foreground text-sm leading-snug">
            {socialProof.text.replace(/\s+/g, " ")}
          </span>
        </div>
      )
    }
  </SectionContainer>
</Section>
